{
  "theme": "moonstone",
  "cssTheme": "Black Atom",
  "enabledCssSnippets": [
    "custom-checkboxes",
    "complete-strikethrough",
    "typo"
  ]
}

/**
 * Black Atom Obsidian Theme — Dev Watch
 *
 * Watches source files and rebuilds on changes:
 * 1. Runs generate (core CLI)
 * 2. Runs postGenerate (assemble theme.css)
 * 3. Copies theme.css + manifest.json to vault (if OBSIDIAN_DEV_VAULT is set)
 *
 * Configure vault path in .env (see .env.example).
 */

import { load } from "@std/dotenv";

await load({ export: true });

const DEBOUNCE_MS = 300;
const WATCH_DIRS = ["themes", "styles"];
const DEV_THEME_NAME = "Black Atom Development";
const DEV_THEME_DIR = "Black Atom Development";

async function run(cmd: string[]): Promise<boolean> {
  const command = new Deno.Command(cmd[0], {
    args: cmd.slice(1),
    stdout: "inherit",
    stderr: "inherit",
  });
  const { code } = await command.output();
  return code === 0;
}

async function rebuild(): Promise<void> {
  console.log("\n--- Rebuilding ---");

  console.log("Generating theme tokens...");
  if (!await run(["deno", "task", "generate"])) {
    console.error("Generate failed, skipping remaining steps.");
    return;
  }

  console.log("Assembling theme.css...");
  if (!await run(["deno", "task", "postGenerate"])) {
    console.error("Post-generate failed, skipping copy.");
    return;
  }

  await copyToVault();
  console.log("--- Done ---\n");
}

function resolveHome(path: string): string {
  if (path.startsWith("~/")) {
    const home = Deno.env.get("HOME");
    if (home) return home + path.slice(1);
  }
  return path;
}

async function copyToVault(): Promise<void> {
  const raw = Deno.env.get("OBSIDIAN_DEV_VAULT");
  if (!raw) return;
  const vaultPath = resolveHome(raw);

  const dest = `${vaultPath}/.obsidian/themes/${DEV_THEME_DIR}`;

  try {
    await Deno.mkdir(dest, { recursive: true });
  } catch (err) {
    if (!(err instanceof Deno.errors.AlreadyExists)) {
      console.error(`Failed to create ${dest}:`, err);
      return;
    }
  }

  try {
    await Deno.copyFile("theme.css", `${dest}/theme.css`);
  } catch (err) {
    console.error("Failed to copy theme.css:", err);
    return;
  }

  try {
    const manifest = JSON.parse(await Deno.readTextFile("manifest.json"));
    manifest.name = DEV_THEME_NAME;
    await Deno.writeTextFile(
      `${dest}/manifest.json`,
      JSON.stringify(manifest, null, 2) + "\n",
    );
  } catch (err) {
    console.error("Failed to write dev manifest:", err);
    return;
  }

  console.log(`Copied to ${dest}`);
}

async function dev(): Promise<void> {
  const raw = Deno.env.get("OBSIDIAN_DEV_VAULT");
  const vaultPath = raw ? resolveHome(raw) : undefined;
  console.log("Black Atom Obsidian — Dev Watch");
  console.log(`Watching: ${WATCH_DIRS.join(", ")}`);
  if (vaultPath) {
    console.log(
      `Vault copy: ${vaultPath}/.obsidian/themes/${DEV_THEME_DIR}`,
    );
  } else {
    console.log(
      "Vault copy: disabled (set OBSIDIAN_DEV_VAULT to enable)",
    );
  }

  // Initial build
  await rebuild();

  // Watch for changes
  const watcher = Deno.watchFs(WATCH_DIRS);
  let timeout: ReturnType<typeof setTimeout> | null = null;

  for await (const event of watcher) {
    // Skip generated files to avoid loops
    const isGenerated = event.paths.some((p) =>
      p.includes("/themes/") && !p.includes(".template.") &&
      p.endsWith(".css")
    );
    if (isGenerated) continue;

    if (timeout) clearTimeout(timeout);
    timeout = setTimeout(() => rebuild(), DEBOUNCE_MS);
  }
}

dev();

/**
 * Build configuration for Black Atom Obsidian theme.
 */
export const config = {
  paths: {
    themes: "themes",
    styles: "styles",
    get ui() {
      return this.styles + "/ui";
    },
    output: "theme.css",
  },

  styleSettingsSections: {
    variants: {
      name: "Black Atom \:\: Variants",
      id: "black-atom-variants",
    },
    ui: {
      name: "Black Atom \:\: UI",
      id: "black-atom-ui",
    },
  },
} as const;

use serde::{Deserialize, Serialize};
use specta::Type;
use std::collections::HashMap;

/// Supported app names. TypeScript bindings are auto-generated via tauri-specta.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize, Type)]
#[serde(rename_all = "lowercase")]
pub enum AppName {
    Nvim,
    Tmux,
    Ghostty,
    Zed,
    Delta,
    Lazygit,
    Obsidian,
}

impl AppName {
    /// All per-app updater variants. Does not include system-level toggles (system_appearance).
    pub const fn all() -> &'static [AppName] {
        &[
            AppName::Nvim,
            AppName::Tmux,
            AppName::Ghostty,
            AppName::Zed,
            AppName::Delta,
            AppName::Lazygit,
            AppName::Obsidian,
        ]
    }

    pub fn as_str(&self) -> &'static str {
        match self {
            AppName::Nvim => "nvim",
            AppName::Tmux => "tmux",
            AppName::Ghostty => "ghostty",
            AppName::Zed => "zed",
            AppName::Delta => "delta",
            AppName::Lazygit => "lazygit",
            AppName::Obsidian => "obsidian",
        }
    }
}

fn default_true() -> bool {
    true
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct AppConfig {
    #[serde(default = "default_true")]
    pub enabled: bool,
    pub config_path: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub themes_path: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub match_pattern: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub replace_template: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct Keymappings {
    pub toggle_window: String,
}

impl Default for Keymappings {
    fn default() -> Self {
        Self {
            toggle_window: "super+ctrl+alt+shift+KeyT".to_string(),
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct Config {
    pub system_appearance: bool,
    #[serde(default)]
    pub keymappings: Keymappings,
    pub apps: HashMap<AppName, AppConfig>,
}

use std::collections::HashMap;

use super::types::{AppConfig, AppName, Config, Keymappings};

impl Default for Config {
    fn default() -> Self {
        let mut apps = HashMap::new();
        apps.insert(
            AppName::Ghostty,
            AppConfig {
                enabled: false,
                config_path: "~/.config/ghostty/config".to_string(),
                themes_path: None,
                match_pattern: Some(r"^theme\s*=\s*.+$".to_string()),
                replace_template: Some("theme = {themeKey}.conf".to_string()),
            },
        );
        apps.insert(
            AppName::Nvim,
            AppConfig {
                enabled: false,
                config_path: "~/.config/nvim/lua/config.lua".to_string(),
                themes_path: None,
                match_pattern: Some(r#"colorscheme\s*=\s*"[^"]*""#.to_string()),
                replace_template: Some(r#"colorscheme = "{themeKey}""#.to_string()),
            },
        );
        apps.insert(
            AppName::Tmux,
            AppConfig {
                enabled: false,
                config_path: "~/.config/tmux/tmux.conf".to_string(),
                themes_path: None, // user must set this to their tmux themes directory
                match_pattern: Some(r"^source-file\s+.+/themes/.+\.conf$".to_string()),
                replace_template: Some(
                    "source-file {themesPath}/{collectionKey}/{themeKey}.conf".to_string(),
                ),
            },
        );
        apps.insert(
            AppName::Delta,
            AppConfig {
                enabled: false,
                config_path: "~/.gitconfig.delta".to_string(),
                themes_path: None,
                match_pattern: Some(r"features\s*=\s*black-atom-(dark|light)".to_string()),
                replace_template: Some("features = black-atom-{appearance}".to_string()),
            },
        );
        apps.insert(
            AppName::Zed,
            AppConfig {
                enabled: false,
                config_path: "~/.config/zed/settings.json".to_string(),
                themes_path: None,
                match_pattern: None, // not used — JSONC editing is structural
                replace_template: None,
            },
        );
        apps.insert(
            AppName::Lazygit,
            AppConfig {
                enabled: false,
                config_path: "~/.config/lazygit/config.yml".to_string(),
                themes_path: None,
                match_pattern: None,
                replace_template: None,
            },
        );
        apps.insert(
            AppName::Obsidian,
            AppConfig {
                enabled: false,
                config_path: String::new(),
                themes_path: None,
                match_pattern: None,
                replace_template: None,
            },
        );
        Config {
            system_appearance: true,
            keymappings: Keymappings::default(),
            apps,
        }
    }
}

