use std::fs;
use std::path::PathBuf;

use super::types::Config;

/// Path to the livery config file.
fn config_path() -> PathBuf {
    let home = match dirs::home_dir() {
        Some(h) => h,
        None => {
            log::warn!("Could not determine home directory, using current directory");
            PathBuf::new()
        }
    };
    home.join(".config")
        .join("black-atom")
        .join("livery")
        .join("config.json")
}

/// Merge user config with defaults — fills in missing fields from the default config.
/// This intentionally hydrates the user's config with all default apps (disabled).
/// When save_config is called, all apps are written to disk — this ensures the config
/// file always contains the full list of supported apps for the settings UI.
fn merge_with_defaults(mut user_config: Config) -> Config {
    let defaults = Config::default();

    for (name, default_app) in &defaults.apps {
        match user_config.apps.get_mut(name) {
            Some(app) => {
                if app.match_pattern.is_none() {
                    app.match_pattern = default_app.match_pattern.clone();
                }
                if app.replace_template.is_none() {
                    app.replace_template = default_app.replace_template.clone();
                }
                if app.vault_paths.is_none() {
                    app.vault_paths = default_app.vault_paths.clone();
                }
            }
            None => {
                user_config.apps.insert(*name, default_app.clone());
            }
        }
    }

    user_config
}

/// Read config from disk and merge with defaults.
pub fn read_config_from_disk() -> Config {
    let path = config_path();
    let user_config = match fs::read_to_string(&path) {
        Ok(content) => match serde_json::from_str(&content) {
            Ok(config) => config,
            Err(e) => {
                log::warn!("Failed to parse config, using defaults: {e}");
                Config::default()
            }
        },
        Err(_) => Config::default(),
    };

    merge_with_defaults(user_config)
}

/// Write config to disk.
pub fn write_config_to_disk(config: &Config) -> Result<(), String> {
    let path = config_path();
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|e| format!("Failed to create config dir: {e}"))?;
    }
    let json =
        serde_json::to_string_pretty(config).map_err(|e| format!("Failed to serialize: {e}"))?;
    fs::write(&path, json).map_err(|e| format!("Failed to write config: {e}"))?;
    Ok(())
}

/// Ensure the config file exists on disk (creates with defaults on first launch).
pub fn ensure_config_exists() {
    let path = config_path();
    if !path.exists() {
        let _ = write_config_to_disk(&Config::default());
    }
}

/// Expand tilde in config_path so the frontend receives absolute paths.
/// Also expands tildes in vault_paths entries.
/// themes_path is NOT expanded — it's used in replace templates and should keep ~ for portability.
pub fn expand_app_paths(config: &mut Config) {
    for app_config in config.apps.values_mut() {
        app_config.config_path = shellexpand::tilde(&app_config.config_path).to_string();
        if let Some(ref mut vaults) = app_config.vault_paths {
            for path in vaults.iter_mut() {
                *path = shellexpand::tilde(path).to_string();
            }
        }
    }
}

/// Re-tilde absolute paths so they are stored portably on disk.
pub fn collapse_app_paths(config: &mut Config) {
    if let Some(home) = dirs::home_dir() {
        let home_prefix = format!("{}/", home.to_string_lossy());
        for app_config in config.apps.values_mut() {
            if app_config.config_path.starts_with(&home_prefix) {
                app_config.config_path =
                    format!("~/{}", &app_config.config_path[home_prefix.len()..]);
            }
            if let Some(ref tp) = app_config.themes_path {
                if tp.starts_with(&home_prefix) {
                    app_config.themes_path = Some(format!("~/{}", &tp[home_prefix.len()..]));
                }
            }
            if let Some(ref mut vaults) = app_config.vault_paths {
                for path in vaults.iter_mut() {
                    if path.starts_with(&home_prefix) {
                        *path = format!("~/{}", &path[home_prefix.len()..]);
                    }
                }
            }
        }
    }
}

use std::path::{Path, PathBuf};

use crate::config::types::AppConfig;

use super::file_ops;
use super::{UpdateContext, UpdateResult};

/// Update Obsidian by patching two JSON files in each vault's `.obsidian/` directory:
///
/// 1. `appearance.json` — sets `theme` to "obsidian" (dark) or "moonstone" (light)
/// 2. `plugins/obsidian-style-settings/data.json` — sets the Black Atom variant key
///
/// `vault_paths` should contain vault root directories. The updater appends `.obsidian/`
/// to each and patches the relevant files within.
pub fn update(app_str: &str, app_config: &AppConfig, ctx: &UpdateContext) -> UpdateResult {
    let vault_paths = match app_config.vault_paths {
        Some(ref paths) if !paths.is_empty() => paths,
        _ => return UpdateResult::error(app_str, "No vault paths configured"),
    };

    let obsidian_theme = match ctx.appearance {
        "dark" => "obsidian",
        "light" => "moonstone",
        other => return UpdateResult::error(app_str, format!("Unknown appearance: {other}")),
    };

    let mut errors = Vec::new();

    for vault_root in vault_paths {
        let obsidian_dir = Path::new(vault_root).join(".obsidian");
        match patch_vault(&obsidian_dir, obsidian_theme, ctx.theme_key) {
            Ok(()) => {
                log::info!("Updated obsidian vault: {}", obsidian_dir.display());
            }
            Err(e) => {
                log::warn!("Failed to update vault {}: {e}", obsidian_dir.display());
                errors.push(format!("{}: {e}", obsidian_dir.display()));
            }
        }
    }

    // If all vaults failed, return error
    if errors.len() == vault_paths.len() {
        return UpdateResult::error(app_str, errors.join("; "));
    }

    // Reload only if Obsidian is already running — the `obsidian` CLI can
    // launch the app and block indefinitely when it isn't.
    // Config files are already patched, so the next Obsidian start picks them up.
    if !is_running() {
        log::info!("Obsidian not running, skipping reload (config patched)");
        if !errors.is_empty() {
            return UpdateResult::skipped(
                app_str,
                format!("Some vaults failed: {}", errors.join("; ")),
            );
        }
        return UpdateResult::done(app_str);
    }

    if let Err(msg) = reload() {
        log::warn!("{msg}");
        return UpdateResult::skipped(
            app_str,
            format!("Config patched; live reload failed: {msg}"),
        );
    }

    if !errors.is_empty() {
        return UpdateResult::skipped(
            app_str,
            format!("Some vaults failed: {}", errors.join("; ")),
        );
    }

    UpdateResult::done(app_str)
}

/// Patch a single vault's appearance.json and style-settings data.json.
fn patch_vault(obsidian_dir: &Path, obsidian_theme: &str, theme_key: &str) -> Result<(), String> {
    let appearance_path = obsidian_dir.join("appearance.json");
    let appearance_str = appearance_path.to_string_lossy().to_string();

    // Patch appearance.json: set base theme mode
    file_ops::jsonc::patch_jsonc_file(appearance_str.clone(), "theme", obsidian_theme)?;

    // Patch style settings: set the variant key for the current appearance
    let style_settings_path = derive_style_settings_path(obsidian_dir);
    if let Some(ss_path) = style_settings_path {
        if ss_path.exists() {
            // Flat JSONC keys — "@@" is the Style Settings plugin separator,
            // not a path delimiter (patch_jsonc_file only splits on ".").
            let variant_key = match obsidian_theme {
                "obsidian" => "black-atom-variants@@dark-theme-variant",
                "moonstone" => "black-atom-variants@@light-theme-variant",
                _ => "black-atom-variants@@light-theme-variant",
            };

            if let Err(e) = file_ops::jsonc::patch_jsonc_file(
                ss_path.to_string_lossy().to_string(),
                variant_key,
                theme_key,
            ) {
                log::warn!("Style settings patch failed (non-fatal): {e}");
            }
        }
    }

    Ok(())
}

/// Derive the style settings data.json path from the `.obsidian/` directory.
/// The style settings file is at `<vault>/.obsidian/plugins/obsidian-style-settings/data.json`.
fn derive_style_settings_path(obsidian_dir: &Path) -> Option<PathBuf> {
    Some(
        obsidian_dir
            .join("plugins")
            .join("obsidian-style-settings")
            .join("data.json"),
    )
}

/// Check whether Obsidian is currently running.
fn is_running() -> bool {
    std::process::Command::new("pgrep")
        .args(["-x", "Obsidian"])
        .output()
        .map(|o| o.status.success())
        .unwrap_or(false)
}

/// Reload the Obsidian vault via the `obsidian` CLI.
/// Only called when Obsidian is already running — the command can launch
/// the app and block indefinitely if it isn't.
fn reload() -> Result<(), String> {
    match std::process::Command::new("obsidian")
        .arg("reload")
        .output()
    {
        Ok(output) => {
            if !output.status.success() {
                log::info!("obsidian reload returned non-zero");
            }
            Ok(())
        }
        Err(e) => Err(format!("Failed to run obsidian reload: {e}")),
    }
}

